sql:
SELECT portfolio_id, SUM(current_value) AS total_value
FROM portfolio_stocks
GROUP BY portfolio_id;

external_knowledge:
; The term 'top-performing users' refers to users with the highest cumulative distribution of their portfolio's percentage gain or loss; 
; The cumulative distribution is a measure of the proportion of users with a portfolio performance less than or equal to a given percentage gain or loss; 
; This allows for a relative ranking of users based on their portfolio's performance.
